再来一个闰年的判断：



import java.util.Scanner;    public class ifdemo {      public static void main(String[] args) {          Scanner sc = new Scanner(System.in);          int year = sc.nextInt();          if(year % 4 == 0 &amp;&amp; year % 100 != 0 || year % 400 == 0) {              System.out.println(year + "是闰年");          }else System.out.println(year + "不是闰年");      }  }
switch 语句注意： swtich 语句中如果不加 break 语句，则从上到下匹配到第一个 case 后，会顺次执行后面每个 case 中的语句。default：表示所有情况都不匹配的时候，就执行该处内容，和if语句中的else相似
import java.util.Scanner;public class Main {    public static void main(String[] args){        Scanner sc = new Scanner(System.in);         System.out.print("请输入一个数字（1-7）代表星期几：");        String name;        int day = sc.nextInt();          switch(day){            case 1:{                name="Monday";                break;            }            case 2:{                name="Tuesday";                break;            }            case 3:{                name="Wednesday";                break;            }            case 4:{                name="Thursday";                break;            }            case 5:{                name="Friday";                break;            }case 6:{                name="Saturday";                break;            }case 7:{                name="Sunday";                break;            }            default: name="I don't know!";        }        System.out.println(name);    }}

for 循环for (init-statement; condition; expression) {    statement}
在循环中需要初始化语句、条件判断语句、条件控制语句。init-statement 可以是声明语句、表达式、空语句，一般用来初始化循环变量；condition 是条件表达式，可以为空，空语句表示 true；expression 一般负责修改循环变量，可以为空。
在一行中输出斐波那契数列的前 N 项，数字之间用空格隔开。
import java.util.Scanner;public class Main{    public static void main(String[] args)    {        Scanner sc = new Scanner(System.in);        int n=sc.nextInt();        int a=0,b=1;        for(int i=0;i&lt;n;i++)        {            System.out.printf("%d ",a);            int c=a+b;            a=b;            b=c;        }    }}
在循环中可能会使用 break 和 continue 语句。比如在判断质数中：
import java.util.Scanner;public class Main{    public static void main(String[] args)    {        Scanner sc=new Scanner(System.in);        int n=sc.nextInt();        boolean isPrime = true;        for(int i=2;i&lt;=n/i;i++)        {            if(n%i==0){                isPrime=false;                break;            }        }        if(isPrime)System.out.println("YES");        else System.out.println("NO");    }}
在求 1~100 的所有偶数之和：
import java.util.Scanner;public class Main{    public static void main(String[] args)    {        int sum=0;        for(int i=1;i&lt;=100;i++)        {            if(i%2==1)continue;            sum+=i;        }        System.out.printf("从1到100的偶数和为：%d",sum);    }}
while 循环这东西其实和 for 循环差不了多少。只不过是括号里只剩了一个条件判断语句。求 1~100 中所有数的立方和：
public class Main{    public static void main(String[] args)    {        int i=1,sum=0;        while(i&lt;=100)        {            sum+=i*i*i;            i++;        }        System.out.println(sum);    }}
do-while 循环do while 语句与 while 语句非常相似。唯一的区别是，do while 语句限制性循环体后检查条件。不管条件的值如何，都要至少执行一次循环。
在写循环的时候一定要注意不要写出死循环

比赛链接：牛客竞赛_ACM/NOI/CSP/CCPC/ICPC算法编程高难度练习赛_牛客竞赛OJ今天先写做出来的题解，明天再写其他的。（PS：个人思路，以官方题解为准）严肃补题👹👹
B Card Game思路：B 题虽说简单吧，比赛时没做出来。最大分数就是比小红最小值大的数字个数，然后把这部分排列一下  种然后剩下的又是  种，最后取乘积再取模。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e5+5;const int MOD=998244353;int a[N];int f[N];void init(){    f[0]=1;    for(int i=1;i&lt;N;i++)    {        f[i]=f[i-1]*i%MOD;    }}void solve(){    int n;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    int m=1e9;    int x;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;x;        m=min(x,m);    }    int cnt=0;    for(int i=1;i&lt;=n;i++)    {        if(a[i]&gt;m)cnt++;    }    cout&lt;&lt;f[cnt]*f[n-cnt]%MOD&lt;&lt;endl;}signed main(){	IOS    init();	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}
C Array Covering思路：可以发现总有办法把数组中最大的数覆盖到除数组两端的位置。所以找到最大值然后进行计算。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=5e5+5;int a[N];void solve(){    int n;    cin&gt;&gt;n;    int maxx=-1;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        maxx=max(a[i],maxx);    }    cout&lt;&lt;maxx*(n-2)+a[1]+a[n]&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}

E Block Game思路：可以把第一个万能方块放进数组中，然后当作一个环去看，开始就是第一个位置和最后一个位置的和之后继续枚举。枚举间距为 n+1 的数之和找到最大的值。这里需要注意的是，值可能是负值。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e5+5;int a[N];void solve(){    int n,k;    cin&gt;&gt;n&gt;&gt;k;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    a[0]=k;    int ans=-2e7;    for(int i=0;i&lt;=n;i++)    {        int last=(i+n)%(n+1);        int sum=a[i]+a[last];        ans=max(sum,ans);    }    cout&lt;&lt;ans&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}

G Digital Folding思路：数字折叠，先写一下数字翻转的写法，不建议用 string 的 reverse ()。拿个循环写就可以，每次取出最后一位，每次乘十也可以去除前导零。然后就是考虑怎么找到最大的数字：可以先把右边的 r 翻转一下，然后考虑把 r 的最右侧位置都一一换成 9，要保证这个数字比 l 大。刚开始的 r 肯定得比 10 大，不然翻不翻转没啥意义。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);int revers(int x){    int res=0;    while(x&gt;0)    {        res=res*10+x%10;        x/=10;    }    return res;}void solve(){    int l,r;    cin&gt;&gt;l&gt;&gt;r;    int ans=revers(r);    int m=10;    while(r&gt;=10)    {        int a=(r/m)*m-1;        if(a&gt;=l)ans=max(ans,revers(a));        if(r/10&lt;m)break;        m*=10;    }    cout&lt;&lt;ans&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}
K Constructive思路：签到题，观察模拟一下可以发现只有 1 和 3 存在其他都是 NO。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);void solve(){    int n;    cin&gt;&gt;n;    if(n==1)cout&lt;&lt;"YES"&lt;&lt;endl&lt;&lt;"1"&lt;&lt;endl;    else if(n==3)cout&lt;&lt;"YES"&lt;&lt;endl&lt;&lt;"1 2 3"&lt;&lt;endl;    else cout&lt;&lt;"NO"&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}
L Need Zero思路：签到题，要让 n 在一次乘积运算后个位为 0，只需要考虑个位数。所以取出个位数，然后给写个数组就可以了。个位本来就是 0 的乘 1 就可以了，其他的背一下乘法表就可以出。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);int a[]={1,10,5,10,5,2,5,10,5,10};void solve(){    int n;    cin&gt;&gt;n;    int t=n%10;    cout&lt;&lt;a[t];}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

依旧开场叠罚时😭😭
A 本场比赛灵感来源于树状数组出题组思路：首先计算以下  个数的  是多少，然后从第一个数到最后一个数遍历，然后再遍历一个循环。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e3+5;int a[N];void solve(){    int n;    cin&gt;&gt;n;    int ans=0;    int ttt=(4*(n-1)+4)/5;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    for(int i=0;i&lt;n;i++)    {        int cnt=0;        for(int j=0;j&lt;n;j++)        {            if(a[j]&lt;=a[i])cnt++;        }        if((cnt-1)&gt;=ttt)ans+=a[i];    }    cout&lt;&lt;ans;}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
B 构造部落思路：记录一下每个首领登基的年份。代码： 
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e5+5;int a[N];int year[N];void solve(){    int n,q,s;    cin&gt;&gt;n&gt;&gt;q&gt;&gt;s;    year[1]=s;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        year[i+1]=year[i]+a[i];    }    while(q--)    {        int x,y;        cin&gt;&gt;x&gt;&gt;y;        cout&lt;&lt;year[x]+y-1&lt;&lt;endl;    }}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}

C 墨提斯的排列思路：要让相邻两项异或值最小，就需要二进制表示只有一位二进制数不同，这种任意两个相邻的代码只有一位二进制数不同的编码称为格雷码。代码： 
void solve(){    int n;    cin&gt;&gt;n;    for(int i=0;i&lt;(1&lt;&lt;n);i++)    {        cout&lt;&lt;(i^(i&gt;&gt;1))&lt;&lt;" ";    }}
I 初华的扭蛋机思路：谨记不要赌博，所以我一个都不押。代码： 
void solve(){    cout&lt;&lt;"######";}
H 时不时使使用玉米加农炮掩饰害羞的邻座艾莉同学思路：这个的话我刚开始感觉是二维前缀和，不过这个图形是个菱形。手画一下，定义一下偏移量数组，用 sc 数组表示该点的得分。记录最大值和对应坐标。每次添加时只遍历地图中的  范围，满足曼哈顿距离的加分，然后不断更新最大值。还是注意开 longlong。
