#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=550;int a[N][N];int sc[505][505];int dx[13]={-2,-1,-1,-1,0,0,0,0,0,1,1,1,2};int dy[13]={0,-1,0,1,-2,-1,0,1,2,-1,0,1,0};void solve(){    int n,m,q;    cin&gt;&gt;n&gt;&gt;m&gt;&gt;q;    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)        {            cin&gt;&gt;a[i][j];        }    }    int ansx,ansy,ma=0;    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)        {            int cnt=0;            for(int d=0;d&lt;13;d++)            {                int xx=i+dx[d];                int yy=j+dy[d];                if(xx&gt;0&amp;&amp;yy&gt;0&amp;&amp;xx&lt;=n&amp;&amp;yy&lt;=m)                {                    cnt+=a[xx][yy];                }            }            sc[i][j]=cnt;            if(sc[i][j]&gt;ma){                ma=sc[i][j];                ansx=i;                ansy=j;            }        }    }    while(q--)    {        int x,y,z;        cin&gt;&gt;x&gt;&gt;y&gt;&gt;z;        a[x][y]+=z;        for(int i=max(1LL,x-2);i&lt;=min(n,x+2);i++)        {            for(int j=max(1LL,y-2);j&lt;=min(m,y+2);j++)            {                if(abs(i-x)+abs(j-y)&lt;=2)                {                    sc[i][j]+=z;                    if(sc[i][j]&gt;ma)                    {                        ansx=i;                        ansy=j;                        ma=sc[i][j];                    }                }            }        }        cout&lt;&lt;ansx&lt;&lt;" "&lt;&lt;ansy&lt;&lt;endl;    }}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
F 爱音的01串构造思路：赛时就想着交替分布了，没想到均匀分布。：将数量较少的字符作为分隔符，数量较多的字符分成尽可能均匀的段。代码： 
#include&lt;bits/stdc++.h&gt;using namespace std;#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define int long long#define endl '\n'void solve(){    int a,b;    cin&gt;&gt;a&gt;&gt;b;    int n=a+b;    string s;    if(a==0){        cout&lt;&lt;string(b,'1')&lt;&lt;endl;        return;    }    if(b==0){        cout&lt;&lt;string(a,'0')&lt;&lt;endl;        return;    }    if(a&gt;=b){        string tt(n,'0');        s=tt;        int d=a/(b+1);//每组至少有d个0        int res=a%(b+1);//前res组每组多一个0        for(int i=d;i&lt;n;i+=d+1)//在字符串中每隔(d+1)个位置放一个1        {            if(res&gt;0)//多放一个0            {                res--;                i++;            }            s[i]='1';        }    }else{        int d=b/(a+1);        int res=b%(a+1);        string tt(n,'1');        s=tt;        for(int i=d;i&lt;n;i+=d+1)        {            if(res&gt;0)            {                res--;                i++;            }            s[i]='0';        }    }    cout&lt;&lt;s&lt;&lt;endl;}signed main(){    int t;    cin&gt;&gt;t;    while(t--)    {        solve();    }}

