K 小L的游戏1思路：问最后一次操作是谁进行的，先计算一下最多能进行多少次两人操作，然后再看是增加 m 超过 z 还是增加 m+n 超过 z。代码：
void solve(){    int m,n,z;    cin&gt;&gt;m&gt;&gt;n&gt;&gt;z;    int cnt=(z-1)/(m+n);    int ans=cnt*(m+n);    if(ans+m&gt;=z)cout&lt;&lt;"0";    else cout&lt;&lt;"1";}
H 小L的数组思路：一共就两种操作，按位异或是不会超过 2048 的所以开个 2048 的数组就可以。用 dp[i] 来表示这个数字能否到达，然后进行 n 步操作，每一步操作都有一个内循环去处理之前操作所能到达的值。注意不要在内循环中直接去修改 dp 数组这样会导致错误，所以先用一个 ne 数组去存储。然后从大到小找所能到达的最大值即可。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'const int N=2100;int a[N],b[N];bool dp[2048],ne[2048];void solve(){    int n;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;b[i];    }    memset(dp,0,sizeof dp);    dp[0]=1;    for(int i=1;i&lt;=n;i++)    {        memset(ne,0,sizeof ne);        for(int x=0;x&lt;2048;x++)        {            if(!dp[x])continue;            int m=max(0LL,x-a[i]);            ne[m]=1;            m=x^b[i];            ne[m]=1;        }        for(int j=0;j&lt;2048;j++)            dp[j]=ne[j];    }    for(int i=2047;i&gt;=0;i--)    {        if(dp[i]){            cout&lt;&lt;i;            break;        }    }}signed main(){    int t=1;    IOS    while(t--)    {        solve();    }}

G 小L的散步思路：首先先来个起步检测，如果一开始就踩缝隙了，直接 YES，用前缀和数组+二分查找来进行之后的判断，用前缀和可以记录每个缝隙的位置，二分去找第一个大于后脚跟的缝隙，之后判断是否猜到缝隙。不要暴力，会超时。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'const int N=2e5+5;int a[N],b[N],s[N];void solve(){    int n,m,l;    cin&gt;&gt;n&gt;&gt;m&gt;&gt;l;    s[0]=0;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        s[i]=s[i-1]+a[i];    }    for(int i=1;i&lt;=m;i++)    {        cin&gt;&gt;b[i];    }    if(l&gt;a[1])    {        cout&lt;&lt;"YES";        return;    }    int last=0;    for(int i=1;i&lt;=m;i++)    {        last+=b[i];        int le=1,r=n,j=-1;        while(le&lt;=r)        {            int mid=(le+r)/2;            if(s[mid]&gt;=last){                j=mid;                r=mid-1;            }else{                le=mid+1;            }        }        if(j!=-1&amp;&amp;s[j]&lt;last+l&amp;&amp;s[j]&gt;last)        {            cout&lt;&lt;"YES";            return;        }//         for(int j=1;j&lt;=n;j++)//         {//             if(s[j]&gt;last&amp;&amp;s[j]&lt;last+l)//             {//                 cout&lt;&lt;"YES";//                 return;//             }//         }    }    cout&lt;&lt;"NO";}signed main(){    int t=1;    IOS    while(t--)    {        solve();    }}
B 小L的彩球思路：要有 t 根线其实就是把这 n 个球分成 t+1 块，有两种情况，奇数块归左边或者是奇数块归右边。所以可以计算出左右两盒的块数，奇数块数在计算时需要上取整。然后其实就是在左边 x 个球中划分出 l 个块，就是 $C^{x-1}{l-1}，右边是C^{y-1}{r-1}$。反之同理。组合数的计算可以等之后会发一篇简单数学。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl "\n"const int MOD=998244353;const int N=1e6+5;int fact[N],infact[N];int qmi(int a,int b){    int res=1;    while(b)    {        if(b&amp;1){            res=a*res%MOD;        }        b&gt;&gt;=1;        a=a*a%MOD;    }    return res;}void pre(){    fact[0]=infact[0]=1;    for(int i=1;i&lt;N;i++)    {        fact[i]=fact[i-1]*i%MOD;//         infact[i]=infact[i-1]*qmi(i,MOD-2)%MOD;    }    infact[N-1]=qmi(fact[N-1],MOD-2);    for(int i=N-2;i&gt;=0;i--){        infact[i]=infact[i+1]*(i+1)%MOD;    }}int C(int n,int k){    if(k&lt;0||k&gt;n)return 0;    return fact[n]*infact[k]%MOD*infact[n-k]%MOD;}void solve(){    int n,x,t;    cin&gt;&gt;n&gt;&gt;x&gt;&gt;t;    if(t==0){        if(x==0||(n-x)==0){            cout&lt;&lt;"1"&lt;&lt;endl;        }else cout&lt;&lt;"0"&lt;&lt;endl;        return;    }    int k=t+1;    int ans=0;    int l=(k+1)/2,r=k/2;    if(l&lt;=x&amp;&amp;r&lt;=n-x&amp;&amp;l&gt;0&amp;&amp;r&gt;0){        ans=(ans+C(x-1,l-1)*C(n-x-1,r-1)%MOD)%MOD;    }    if(r&lt;=x&amp;&amp;l&lt;=n-x&amp;&amp;l&gt;0&amp;&amp;r&gt;0){        ans=(ans+C(x-1,r-1)*C(n-x-1,l-1)%MOD)%MOD;    }    cout&lt;&lt;ans&lt;&lt;endl;}signed main(){	IOS	int T;	cin&gt;&gt;T;    pre();	//int t=1;	while(T--)	{		solve();	}}
A 小L的三角尺思路：考察数学的，首先明确三角形的斜边长度是两直角边的平方和。那么打磨后的斜边长为 ，对这个函数对 t 求导得 。可以把这个看成一个单位贡献值，也就是打磨 1 单位长度后斜边减少多少。这个值随着 t 得增加而减少。将这个单位贡献值从大到小进行排列，每次打磨一单位后重新计算。用优先队列来存储。然后就是简单的计算了，最后一个循环把现在的斜边长计算出来。
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define x first#define y second#define endl "\n"#define PII pair&lt;double,int&gt;const int N=5e5+5;int a[N],b[N];double r[N];double cal(int i)//用来计算单位贡献值{    if(r[i]&lt;=0)return 0.0;    else return r[i]/sqrt(1.0*a[i]*a[i]+r[i]*r[i]);}void solve(){    int n,w;    cin&gt;&gt;n&gt;&gt;w;    double sum=0;    int total=0;    int aa=0;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i]&gt;&gt;b[i];        r[i]=b[i];        aa+=a[i];        total+=b[i];        sum+=sqrt(1.0*a[i]*a[i]+1.0*b[i]*b[i]);    }    if(w&gt;=total){//惊天刚试了一下这个特判可以不用        cout&lt;&lt;fixed&lt;&lt;setprecision(9)&lt;&lt;aa;        return;    }    priority_queue&lt;PII&gt; p;//大根堆所以不用greater&lt;&gt;    for(int i=1;i&lt;=n;i++)    {        p.push({cal(i*1LL),i});    }    while(w&amp;&amp;!p.empty())    {        auto [f,i]=p.top();//取出当前最高贡献的        p.pop();        if(f=0)break;        if(r[i]&lt;=0)continue;        w--;//打磨一单位        r[i]--;//打磨一单位        p.push({cal(i*1LL),i});//重新计算贡献后入队    }    double ans=0;    for(int i=1;i&lt;=n;i++)    {        ans+=sqrt(1.0*a[i]*a[i]+r[i]*r[i]);    }    cout&lt;&lt;fixed&lt;&lt;setprecision(9)&lt;&lt;ans;}signed main(){	IOS    int t=1;	while(t--)	{		solve();	}}

