F - Eating Candies链接：Problem - 1669F - Codeforces这是一个双指针问题，一个从前往后扫，另一个从后往前扫，所实现的就是前扫的和等于后扫的和。要使所得到的糖果总数最多。这里可以在前=后时记录下此时的糖果总数，然后对它取 max 就可以。
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e5+5;void solve(){    int n;    cin&gt;&gt;n;    int w[N];    for(int i=0;i&lt;n;i++)cin&gt;&gt;w[i];    int l=0,r=n-1;    int sum1=0,sum2=0;    int ans=0;    while(l&lt;=r)    {        sum1+=w[l];        while(l&lt;r&amp;&amp;sum1&gt;sum2)sum2+=w[r--];//当前后不等的时后加后面        if(sum1==sum2) ans=max(ans,l+n-r);        l++;    }    cout&lt;&lt;ans&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}

G - Same Parity Summands链接：Problem - 1352B - Codeforces要把 n 拆分成 k 个奇偶性相同的数。想一下一个奇数能不能拆分成偶数个？答案是不能。这里指的是拆分成奇偶性相同的数。这可以作为一个判断条件。那一个偶数能不能拆分成奇数个？需要特殊判断一下，要拆分成偶数，最小的偶数是 2，所以 n 必须大于等于 2*k。当 k&gt;n 时也不可能实现，当 k =n 时可以实现 (输出 k 个 1)。这样之后，对于一个奇数，拆分成奇数个，可以拆分成 k-1 个 1 和 n-k+1。（偶数个 1 加上一个奇数）。偶数+奇数=奇数
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);void solve(){    int n,k;    cin&gt;&gt;n&gt;&gt;k;    if(k&gt;n){        cout&lt;&lt;"NO"&lt;&lt;endl;        return;    }    if(n%2&amp;&amp;k%2==0)    {        cout&lt;&lt;"NO"&lt;&lt;endl;        return;    }    if(n==k)    {        cout&lt;&lt;"YES"&lt;&lt;endl;        for(int i=1;i&lt;=k;i++)cout&lt;&lt;"1 ";        cout&lt;&lt;endl;        return;    }    if(n%2)    {        cout&lt;&lt;"YES"&lt;&lt;endl;        for(int i=1;i&lt;=k-1;i++)cout&lt;&lt;"1 ";        cout&lt;&lt;n-k+1&lt;&lt;endl;    }else{        if(k%2&amp;&amp;n&lt;2*k)        {        cout&lt;&lt;"NO"&lt;&lt;endl;        return;        }        cout&lt;&lt;"YES"&lt;&lt;endl;        if(n&lt;2*k)        {            for(int i=1;i&lt;=k-1;i++)cout&lt;&lt;"1 ";            cout&lt;&lt;n-k+1&lt;&lt;endl;        }else{            for(int i=1;i&lt;=k-1;i++)cout&lt;&lt;"2 ";            cout&lt;&lt;n-2*(k-1)&lt;&lt;endl;        }    }}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}

H - K-th Not Divisible by n链接：Problem - 1352C - Codeforces
来分析一下第一个示例3 7不能被三整除的数1 2 4 5 7 8 10 11 13第七个是10再看4 121 2 3 5 6 7 9 10 11 13 14 15 17 18 19我们可以发现被划分成每部分有(4-1)个元素
所以 （n-1）个数为一组，那么 k 中有几个这样的组呢? k/(n-1) 个，那么剩下的一个组有几个数呢？k%(n-1) 个。所以最终结果就是 k/(n-1)*n+k%(n-1)如果 k 能够整除 n-1 时，此时需要减一。(PS: 怎么思考呢，就是我们在乘 n 操作时是认为前面有 k/(n-1) 个完整的组，然后加上余数，但是如果没有余数此时的这个树是可以被 n 整除的，此时最后一个组其实是不完整的，并没有走到最后一个位置，所以减一)
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);void solve(){    int n,k;    cin&gt;&gt;n&gt;&gt;k;    int a=k/(n-1);    int b=k%(n-1);    if(b)cout&lt;&lt;a*n+b&lt;&lt;endl;    else cout&lt;&lt;a*n+b-1&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	//int t=1;	while(t--)	{		solve();	}}

