传纸条题目链接：P1006 [NOIP 2008 提高组] 传纸条 - 洛谷思路：这个题目同上面方格取数的思路，这里的好感度可以看作是格子里的数字，每个数字只能用一次。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'const int N=55;int w[N][N];int dp[2*N][N][N];void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)        {            cin&gt;&gt;w[i][j];        }    }    for(int k=2;k&lt;=n+m;k++){        for(int i1=1;i1&lt;=n;i1++)        {            for(int i2=1;i2&lt;=n;i2++)            {                int j1=k-i1,j2=k-i2;                if(j1&gt;0&amp;&amp;j2&gt;0&amp;&amp;j1&lt;=m&amp;&amp;j2&lt;=m){                    int t=w[i1][j1];                    if(i1!=i2)t+=w[i2][j2];                    int &amp;x=dp[k][i1][i2];                    x=max(x,dp[k-1][i1-1][i2-1]+t);                    x=max(x,dp[k-1][i1-1][i2]+t);                    x=max(x,dp[k-1][i1][i2-1]+t);                    x=max(x,dp[k-1][i1][i2]+t);                }            }        }    }    cout&lt;&lt;dp[m+n][n][n];}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
线性 dp–最长上升子序列模型最长上升子序列题目链接：B3637 最长上升子序列 - 洛谷思路：用 f[i] 表示所有以 a[i] 结尾的严格单调上升子序列长度，初始时 f[i]=1 ，枚举序列的倒数第二个数，用 j(0&lt;j&lt;i) 来表示，若 a[j]&lt;a[i] 则 f[i]=max(f[i],f[j]+1)。代码：
const int N=5500;int a[N];int f[N];void solve(){    int n;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        f[i]=1;    }    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;i;j++)        {            if(a[i]&gt;a[j])            f[i]=max(f[i],f[j]+1);        }    }    int ans=0;    for(int i=1;i&lt;=n;i++)ans=max(ans,f[i]);    cout&lt;&lt;ans;}
使用二分查找可以减少时间复杂度，对于新进来的元素 a[i]，如果 a[i] 大于 f[cnt]，则 f 数组长度加一，将 a[i] 添加进去。反之用 a[i] 替换掉 f 数组中第一个大于或者等于 a[i] 的元素。这样虽然 f 数组中存的不是最长上升子序列，但是长度是相等的。
const int N=1e5+5;int a[N];int f[N];int cnt;int find(int x){    int l=1,r=cnt;    while(l&lt;r){        int mid=(l+r)&gt;&gt;1;        if(f[mid]&gt;=x){            r=mid;        }else l=mid+1;    }    return l;}void solve(){    int n;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    f[++cnt]=a[1];    for(int i=2;i&lt;=n;i++)    {        if(f[cnt]&lt;a[i])f[++cnt]=a[i];        else{            int idx=find(a[i]);            f[idx]=a[i];        }    }    cout&lt;&lt;cnt;}

怪盗基德的滑翔翼题目链接：U234151 怪盗基德的滑翔翼 - 洛谷思路：这个题其实就是求一个最长下降子序列，可以选任意楼为起点，假如选择 a[i] 为起点，那么最长距离为以 a[i] 为结尾的最长上升子序列。所以可以正向做一次反向再求一次得到答案最大值。代码：
const int N=1e5+5;int a[N];int f[N];int b[N];void solve(){    int n;    cin&gt;&gt;n;    memset(b,0,sizeof b);    memset(f,0,sizeof f);    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        f[i]=1;        b[i]=1;//这里用了两个数组可能不好看    }    for(int i=n;i&gt;0;i--)    {        for(int j=n;j&gt;i;j--){            if(a[j]&lt;a[i])            f[i]=max(f[i],f[j]+1);        }    }    int ans=0;    // for(int i=1;i&lt;=n;i++)    // {    //     ans=max(ans,f[i]);    // }    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;i;j++)        {            if(a[j]&lt;a[i])b[i]=max(b[i],b[j]+1);        }    }    for(int i=1;i&lt;=n;i++)    {        ans=max(ans,max(f[i],b[i]));    }    cout&lt;&lt;ans&lt;&lt;endl;}
登山题目链接：U247946 登山 - 洛谷思路：这里的要求一旦开始下降就不能再上升，相邻两个景点的海拔不能相同。按照编号递增顺序来浏览，那么就是先单调上升再单调下降。这样我们就要在中间选一个点，分别向两边走，取最大值。这样的话就先从左向右做一遍最长上升子序列再从右向左做一遍最长上升子序列，再进行枚举答案取最大值即可。代码：
const int N=1e5+5;int a[N];int f[N],b[N];void solve(){    int n;    cin&gt;&gt;n;    memset(f,0,sizeof f);    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    int ans=0;    for(int i=1;i&lt;=n;i++)    {        f[i]=1;        for(int j=1;j&lt;i;j++)        {            if(a[j]&lt;a[i])f[i]=max(f[i],f[j]+1);        }    }    for(int i=n;i&gt;0;i--){        b[i]=1;        for(int j=n;j&gt;i;j--){            if(a[j]&lt;a[i])b[i]=max(b[i],b[j]+1);        }    }    for(int i=1;i&lt;=n;i++)    {        ans=max(ans,f[i]+b[i]-1);    }    cout&lt;&lt;ans&lt;&lt;endl;}
合唱队形题目链接：P1091 [NOIP 2004 提高组] 合唱队形 - 洛谷思路：这个题目要求最少的出队人数，那么其实和上一题是相似的，我们找到满足这个类型队伍的最大值，用 n 减去即可。代码：代码只需要将输出修改为 cout&lt;&lt;n-ans&lt;&lt;endl。
友好城市题目链接：P2782 友好城市 - 洛谷思路：先把一边排序，另一边的最长上升子序列的长度就是最多的的数量，一边已经确定好顺序了，只要保证另一边也是升序，就一定不会交叉。只用 dp 会超时，用二分优化。同样的用一个数组 f 来存，如果 a[i] 大于 f 最后一个数那么就可以放进去，长度加一。反之则找 f 数组中第一个大于 a[i] 的数替换。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;#define x first#define y secondconst int N=2e5+5;PII a[N];int f[N],b[N];void solve(){    int n;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i].x;        cin&gt;&gt;a[i].y;    }    sort(a+1,a+1+n);    int cnt=0;    f[++cnt]=a[1].y;    for(int i=2;i&lt;=n;i++)    {        if(a[i].y&gt;f[cnt])f[++cnt]=a[i].y;        else{            int idx=upper_bound(f+1,f+cnt+1,a[i].y)-f;            f[idx]=a[i].y;        }            }    cout&lt;&lt;cnt;}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
最大上升子序列和题目链接：T285024 最大上升子序列和 - 洛谷思路：这个题目使用 f[i] 表示所有以 a[i] 结尾的上升子序列和的最大值。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;#define x first#define y secondconst int N=2e5+5;int a[N];void solve(){    int n;    cin&gt;&gt;n;    vector&lt;int&gt; f(n+5);    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        f[i]=a[i];    }    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;i;j++)        {            if(a[j]&lt;a[i])f[i]=max(f[i],f[j]+a[i]);        }    }    int ans=*max_element(f.begin(),f.end());    cout&lt;&lt;ans;}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
导弹拦截题目链接：P1020 [NOIP 1999 提高组] 导弹拦截 - 洛谷思路：第一问求最长不上升子序列。第二问考虑贪心：对于每个数，如果现有的子序列的结尾都小于当前数字，那么开一个新的子序列。否则将它放到结尾大于等于它的最小子序列的后面。不会证明 🥱代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;#define x first#define y secondconst int N=2e5+5;int q[N];int a[N];int f[N];int cnt=0;void solve(){    int n=0,x;    while(cin&gt;&gt;x){        a[++n]=x;    }    f[++cnt]=a[1];    for(int i=2;i&lt;=n;i++)    {        if(f[cnt]&gt;=a[i])f[++cnt]=a[i];        else{            int idx=upper_bound(f+1,f+1+cnt,a[i],greater&lt;int&gt;())-f;            f[idx]=a[i];        }    }    cout&lt;&lt;cnt&lt;&lt;endl;    memset(q,0x3f,sizeof q);    cnt=1;    for(int i=1;i&lt;=n;i++)    {        if(q[cnt]&gt;=a[i]){            int idx=lower_bound(q+1,q+1+cnt,a[i])-q;            q[idx]=a[i];        }else{            q[++cnt]=a[i];        }    }    cout&lt;&lt;cnt;}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}
最长公共子序列题目链接：897. 最长公共子序列 - AcWing题库思路：用 f[i][j] 表示 a 的前 i  个字母，和 b 的前 j 个字母的最长公共子序列长度。以 a[i] 、b[j] 是否在子序列中划分为四类：

a[i] 不在，b[j] 不在 此时 max = f[i-1][j-1]。
a[i] 在，b[j] 不在 此时 max=f[i−1][j]。
a[i] 不在，b[j] 在 此时 max=f[i][j-1]。
a[i] 在，b[j] 在 此时 max = f[i-1][j-1]+1 。1）情况是包含在 2）3）中的。代码：

#include &lt;bits/stdc++.h&gt;using namespace std;#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define int long long#define endl '\n'const int N=1010;char a[N],b[N];int n,m;int f[N][N];void solve(){    cin&gt;&gt;n&gt;&gt;m;    cin&gt;&gt;a+1&gt;&gt;b+1;    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)        {            f[i][j]=max(f[i-1][j],f[i][j-1]);            if(a[i]==b[j])f[i][j]=max(f[i][j],f[i-1][j-1]+1);        }    }    cout&lt;&lt;f[n][m];}signed main(){    IOS    int t=1;    while(t--){        solve();    }}
两个排列的最长公共子序列题目链接：P1439 两个排列的最长公共子序列 - 洛谷思路：这个题目用上面的方法会超时。我们可以把第一个序列中第 i 个数映射为 i，在第二个序列中也进行修改。比如原序列为 A={1,2,5,4,3} B={5,3,4,2,1} 映射后为 A={1,2,3,4,5} B={3,5,4,2,1} 这样将求最长公共子序列问题转为求 B 序列的最长上升子序列。这样就可以用二分优化。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define int long long#define endl '\n'const int N=1e5+5;int a[N],b[N];int n;int f[N];void solve(){    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        int x;        cin&gt;&gt;x;        a[x]=i;//这样使用A数组存储映射关系，方便B数组查询。    }    for(int i=1;i&lt;=n;i++)    {        int x;        cin&gt;&gt;x;        b[i]=a[x];    }    int cnt=0;    f[++cnt]=b[1];    for(int i=2;i&lt;=n;i++){        if(b[i]&gt;f[cnt])f[++cnt]=b[i];        else{            int idx=lower_bound(f+1,f+1+cnt,b[i])-f;            f[idx]=b[i];        }    }    cout&lt;&lt;cnt;}signed main(){    IOS    int t=1;    while(t--){        solve();    }}
Missile Defence System题目链接：P10490 Missile Defence System - 洛谷思路：一个导弹有四种选择：1）用一个已经建立好的递增拦截装置拦截；2）用一个已经建立好的递减拦截装置拦截；3）新建一个递增拦截装置；4）新建一个递减拦截装置。考虑深搜 DFS，我们要进行搜索这颗导弹属于上升子序列还是下降子序列，搜索这颗导弹属于哪一个上升/下降子序列。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;#define x first#define y secondconst int N=55;int up[N],down[N];int a[N];int ans;int n;//前u个导弹\上升系统个数su\和下降系统个数sdvoid dfs(int idx,int su,int sd){    if(su+sd&gt;=ans)return;    //最优性剪枝：当目前答案已经大于已知最优答案时，直接回溯    if(idx==n){        ans=su+sd;        return;    }    /*    使用上升系统拦截。    如果当前已有的上升拦截系统的高度都大于第u个导弹高度，则重新开一套系统    否则，就找到当前低于第u个导弹最高拦截系统来负责拦截    */    int k=0;    while(k&lt;su&amp;&amp;up[k]&gt;=a[idx])k++;    int t=up[k];    up[k]=a[idx];    if(k&gt;=su)dfs(idx+1,su+1,sd);    else dfs(idx+1,su,sd);    up[k]=t;//恢复现场    /*    用下降拦截系统来拦截    如果当前已有的下降拦截系统的高度都小于第u个导弹高度，则重新开一套系统    否则，则由当前大于第u个导弹最低拦截系统来负责拦截    */    k=0;    while(k&lt;sd&amp;&amp;down[k]&lt;=a[idx])k++;    t=down[k];    down[k]=a[idx];    if(k&gt;=sd)dfs(idx+1,su,sd+1);    else dfs(idx+1,su,sd);    down[k]=t;}void solve(){    while(cin&gt;&gt;n){        if(n==0)break;        for(int i=0;i&lt;n;i++)cin&gt;&gt;a[i];        ans=n;        dfs(0,0,0);        cout&lt;&lt;ans&lt;&lt;endl;    }}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}

LCIS题目链接：P10954 LCIS - 洛谷思路：设 f[i][j] 表示 a 的前 i 个数和 b 的前 j 个数并以 b[j] 结尾的最大长度。当 a[i]=b[j] 时，只需要在前面找到一个可以把 b[j] 接上去的最长公共上升子序列，答案为 max(f[i-1][k])+1。当 a[i]≠b[j] 时，f[i][j]=f[i-1][j]代码：
/*三重循环做法*/const int N=3100;int a[N],b[N];int n;int f[N][N];void solve(){    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)cin&gt;&gt;a[i];    for(int i=1;i&lt;=n;i++)cin&gt;&gt;b[i];    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=n;j++)        {            f[i][j]=f[i-1][j];            if(a[i]==b[j]){                int mx=0;                for(int k=1;k&lt;j;k++){                    if(b[k]&lt;b[j])                        mx=max(mx,f[i-1][k]);                }                f[i][j]=mx+1;            }        }    }    int ans=0;    for(int i=1;i&lt;=n;i++)    {        ans=max(ans,f[n][i]);    }    cout&lt;&lt;ans;}/*	可以发现每次循环所得到的mx值满足a[i]&gt;b[k]的f[i-1][k]+1的前缀最大值，所以我们直接将这步提出来。*/const int N=3100;int a[N],b[N];int n;int f[N][N];void solve(){    cin&gt;&gt;n;    for(int i=1;i&lt;=n;i++)cin&gt;&gt;a[i];    for(int i=1;i&lt;=n;i++)cin&gt;&gt;b[i];    for(int i=1;i&lt;=n;i++)    {        int mx=0;        for(int j=1;j&lt;=n;j++)        {            if(a[i]!=b[j])f[i][j]=f[i-1][j];            if(a[i]==b[j])f[i][j]=max(mx,f[i][j])+1;            if(a[i]&gt;b[j])mx=max(mx,f[i-1][j]);        }    }    int ans=0;    for(int i=1;i&lt;=n;i++)    {        ans=max(ans,f[n][i]);    }    cout&lt;&lt;ans;}

01 背包01背包问题题目链接：U225269 01背包问题 - 洛谷思路：设 f[i][j] 表示前 i 件物品放入容量为 j 的背包的最大价值。如果当前物品不能放入, 此时没得选了，只能从前 i-1 件物品最优解转移过来，则 f[i][j]=f[i-1][j]。如果能放入则比较价值：f[i][j]=max(f[i-1][j],f[i-1][j-v[i]]+w[i])。代码：
const int N=1050;int v[N],w[N];int f[N][N];void solve(){    int n,m;    cin&gt;&gt;m&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;v[i]&gt;&gt;w[i];    }    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)        {            if(j&lt;v[i])f[i][j]=f[i-1][j];            else f[i][j]=max(f[i-1][j],f[i-1][j-v[i]]+w[i]);        }    }    cout&lt;&lt;f[n][m]&lt;&lt;endl;}
现在在时间上无法优化了，还可以优化空间。可以将 f[i][j] 优化到一维 f[j] 表示 N 件物品，背包容量为 j 下的最优解。为什么可以这样优化，可以看出每次求 f[i][j] 只依赖于 f[i-1][]，所以不需要保留之前的 f[i-2][] 等状态值。一维情况下需要逆序遍历背包容量。当我们更新索引值较大的值时，需要用到之前的状态 f[j-v[i]]，要保证这个状态不被更新掉，例如我们在第 i 轮对体积为 4 的物品进行决策，则状态 f[8] 由 f[4] 更新而来，这里的 f[4] 应该是 f[i-1][4]，如果是正序枚举的话会变为 f[i][4]，所以我们需要逆序更新，使 f[4] 还没有在第 i 轮计算。
/*修改后的for循环*/for(int i=1;i&lt;=n;i++){    for(int j=m;j&gt;=0;j--)    {        if(j&lt;v[i])f[j]=f[j];//优化后这句话没什么用了        else{            f[j]=max(f[j],f[j-v[i]]+w[i]);        }    }}/*可以注意到只有j&gt;=v[i]时才会进行更新，所以for循环还可以写为以下形式。*/for(int i=1;i&lt;=n;i++){    for(int j=m;j&gt;=v[i];j--)    {        f[j]=max(f[j],f[j-v[i]]+w[i]);    }}/*由于我们在循环中是一个一个枚举的并不需要开两个数组，所以还可以优化输入*/for(int i=1;i&lt;=n;i++){    cin&gt;&gt;v&gt;&gt;w;    for(int j=m;j&gt;=v[i];j--)    {        f[j]=max(f[j],f[j-v]+w);    }}
采药题目链接：P1048 [NOIP 2005 普及组] 采药 - 洛谷思路：在这个题目中每种草药只有一株，时间 T 就是背包的容量，要实现价值的最大化。所以上一题代码即可通过。代码：
