const int N=1010;const int MOD=1e9+7;int f[N];int c[N];void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    int v,w;    for(int i=0;i&lt;=m;i++)c[i]=1;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;v&gt;&gt;w;        for(int j=m;j&gt;=v;j--)        {            if(f[j-v]+w&gt;f[j]){                f[j]=f[j-v]+w;                c[j]=c[j-v];//方案数没有改变            }else if(f[j-v]+w==f[j]){                c[j]=(c[j-v]+c[j])%MOD;//装+不装            }        }    }    cout&lt;&lt;c[m];}
