货币系统题目链接：P5020 [NOIP 2018 提高组] 货币系统 - 洛谷思路：考虑每个 a[i] 是否能被之前的数表示，如果可以那么就不需要这个数。所以遍历数组，如果当前数的被表示次数不为 1 则能够被其它数表示出来。代码：
const int N=110;const int M=25005;int a[N];int f[M];void solve(){    int n;    cin&gt;&gt;n;    memset(f,-0x3f,sizeof f);    for(int i=1;i&lt;=n;i++)cin&gt;&gt;a[i];    f[0]=0;    int ans=0;    for(int i=1;i&lt;=n;i++)    {        for(int j=a[i];j&lt;M;j++){            f[j]=max(f[j],f[j-a[i]]+1);        }    }    for(int i=1;i&lt;=n;i++){        if(f[a[i]]==1)ans++;    }    cout&lt;&lt;ans&lt;&lt;endl;}
多重背包朴素多重背包：（适合在物品数量少的时候使用）状态表示：f[i][j] 表示从前 i 个物品中选总体积不超过 j 的方案的最大价值。和完全背包不同的是有数量限制，所以在枚举时需要添加限制。
/*二维版本*/void solve(){    cin&gt;&gt;n&gt;&gt;m;//表示物品数量和背包容量    int v,w,s;//分别表示体积、价值、数量    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;v&gt;&gt;w&gt;&gt;s;        for(int j=0;j&lt;=m;j++)        {            for(int k=0;k&lt;=s&amp;&amp;k*v&lt;=j;k++)            {                f[i][j]=max(f[i][j],f[i-1][j-k*v]+w*k);            }        }    }    cout&lt;&lt;f[n][m];}/*优化到一维*/void solve(){    cin&gt;&gt;n&gt;&gt;m;//表示物品数量和背包容量    int v,w,s;//分别表示体积、价值、数量    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;v&gt;&gt;w&gt;&gt;s;        for(int j=m;j&gt;=v;j--)        {            for(int k=0;k&lt;=s&amp;&amp;k*v&lt;=j;k++)            {                f[j]=max(f[j],f[j-k*v]+w*k);            }        }    }    cout&lt;&lt;f[m];}
二进制优化：当物品个数很多时，一个一个枚举并不合适。利用倍增思想和二进制，可以知道一个十进制数是可以转化为一个二进制比特串，进而可以表示为  和的形式。比如一个物品有 10 个那可以拆分成 ，这样可以拆分成三个箱子，一个有 8 个物品，一个有 2 个物品，转化为 01 背包的思路，只需要判断这个箱子选不选就可以了。这里注意一下，我们相当于是吧每个物品都划分成了  +1个箱子，这样一共 N 个数最后数组需要开 ，所以 f 数组肯定不能开二维了。拆分之后其实就是 cnt 个背包。之后运用 01 背包代码求解。
int v[M],w[M];int f[M];void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    int cnt=1;    for(int i=1;i&lt;=n;i++)    {        int a,b,s;        cin&gt;&gt;a&gt;&gt;b&gt;&gt;s;        for(int j=1;j&lt;=s;j&lt;&lt;=1){//进行二进制拆分            v[cnt]=j*a;            w[cnt++]=j*b;            s-=j;        }        if(s){//处理剩余            v[cnt]=s*a;            w[cnt++]=s*b;        }    }    n=cnt;    for(int i=1;i&lt;=n;i++)    {        for(int j=m;j&gt;=v[i];j--)        {            f[j]=max(f[j],f[j-v[i]]+w[i]);        }    }    cout&lt;&lt;f[m]&lt;&lt;endl;}

单调队列：题目链接：P1886 【模板】单调队列 / 滑动窗口 - 洛谷思路：暴力做法就是以 f[i] 为以 i 结尾的窗口的最小值，用两重循环去做。可以使用单调队列将第二层枚举优化掉。单调队列：队头出队，队尾进队出队。当队列不空且新元素更优时，旧元素从队尾出队。每个元素必然从队尾入队一次。当队头元素滑出窗口时，从队头出队。在队列中存储数组下标方便判断队头出队。代码：
const int N=1e6+5;int a[N];int q[N];void solve()//一维写法{    int n,k;    cin&gt;&gt;n&gt;&gt;k;    int h=1,t=0;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];    }    for(int i=1;i&lt;=n;i++)    {        while(h&lt;=t&amp;&amp;a[q[t]]&gt;=a[i])t--;//队列不空且新元素更优时队尾出队        q[++t]=i;//队尾入队        if(q[h]&lt;i-k+1)h++;//队头元素滑出窗口        if(i&gt;=k)cout&lt;&lt;a[q[h]]&lt;&lt;" ";    }    cout&lt;&lt;endl;    h=1,t=0;    for(int i=1;i&lt;=n;i++)    {        while(h&lt;=t&amp;&amp;a[q[t]]&lt;=a[i])t--;//队列不空且新元素更优时队尾出队        q[++t]=i;//队尾入队        if(q[h]&lt;i-k+1)h++;//队头元素滑出窗口        if(i&gt;=k)cout&lt;&lt;a[q[h]]&lt;&lt;" ";    }}
连续子序列的最大和：题目链接：信息学奥赛一本通（C++版）在线评测系统思路：使用单调队列+前缀和数组，区间范围为 m，队列首元素为区间最小值，用区间内的前缀和减去最小值得到序列中的最大值。代码：
void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        s[i]=s[i-1]+a[i];    }    int h=0,t=0,ans;    q[0]=0,ans=s[1];    for(int i=1;i&lt;=n;i++)    {        if(h&lt;=t&amp;&amp;q[h]&lt;i-m)h++;//队头出队。队列中储存的是前缀和数组下标所以减一        ans=max(ans,s[i]-s[q[h]]);//使用队头最小值计算        while(h&lt;=t&amp;&amp;s[q[t]]&gt;=s[i])t--;//队列不空且新元素更        q[++t]=i;    }    cout&lt;&lt;ans;}
单调队列优化：通过在朴素版本添加输出观察可得，f 数组是按类更新的，可以把 f[0...m] 按体积 v 的余数划分成 v 个类。f[j] 是由前面不超过 s 的同类值递推得到的，相当于从前面宽度为 s 的窗口挑选最大值来更新当前值。所以用单调队列来维护最大值。代码：
int f[M],g[M];int q[M];int v,w,s;void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        memcpy(g,f,sizeof f);//将f拷贝到g        cin&gt;&gt;v&gt;&gt;w&gt;&gt;s;        for(int j=0;j&lt;v;j++)//分成v个类        {            int h=0,t=-1;            for(int k=j;k&lt;=m;k+=v)//对每个类使用单调队列            {                //当q[h]不在窗口[k-s*v,k-v]时出队                if(h&lt;=t&amp;&amp;q[h]&lt;k-s*v)h++;                //使用队头最大值更新f                if(h&lt;=t)f[k]=max(g[k],g[q[h]]+(k-q[h])/v*w);                //当前值更大队尾出队                while(h&lt;=t&amp;&amp;g[k]&gt;=g[q[t]]+(k-q[t])/v*w)t--;                q[++t]=k;            }        }    }    cout&lt;&lt;f[m];}
