分组背包分组背包问题题目链接：U280369 分组背包问题 - 洛谷思路：用 f[i][j] 表示前 i 组物品放入容量为 j 的背包的方案集合的最大值。对于第 i 组物品有以下 s+1 种方案：1）一个都不选，f[i][j]=f[i-1][j]。2）选第 i 组的第 1 个物品，f[i][j]=f[i-1][j-v[1]]+w[1]。…s+1）选第 i 组的第 k 个物品，f[i][j]=f[i-1][j-v[k]]+w[k]。所以状态转移公式为 f[i][j]=max(f[i][j],f[i-1][j-v[k]]+w[k]) 。代码：
const int N=110;int s[N];int v[N][N],w[N][N];int f[N][N];void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;s[i];        for(int j=1;j&lt;=s[i];j++)cin&gt;&gt;v[i][j]&gt;&gt;w[i][j];    }    for(int i=1;i&lt;=n;i++)    {        for(int j=0;j&lt;=m;j++)        {            for(int k=0;k&lt;=s[i]&amp;&amp;j&gt;=v[i][k];k++)            {                f[i][j]=max(f[i][j],f[i-1][j-v[i][k]]+w[i][k]);            }        }    }    cout&lt;&lt;f[n][m];}/*一维数组版本*/void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;s[i];        for(int j=1;j&lt;=s[i];j++)cin&gt;&gt;v[i][j]&gt;&gt;w[i][j];    }    for(int i=1;i&lt;=n;i++)    {        for(int j=m;j&gt;=0;j--)        {            for(int k=0;k&lt;=s[i]&amp;&amp;j&gt;=v[i][k];k++)                f[j]=max(f[j],f[j-v[i][k]]+w[i][k]);        }    }    cout&lt;&lt;f[m];}
机器分配题目链接：P2066 机器分配 - 洛谷思路：这个题目也可可以转换为分组背包问题，把每个公司看成一个分组。求具体方案类比于上面的 01 背包求具体方案，倒着枚举让最优解落到 f[1][m]，同时记录记录 f[i][j] 取到最大值时，第 i 家公司占有的机器数量。反向DP先决策后面的公司再决策前面的公司，当盈利相等时，保留前面公司（编号小）分配更少的方案。这里是 &lt;。当使用 &lt;= 时得到的答案就是编号小的公司尽量多分配。代码：
const int N=100;int f[N][N];int w[N][N];int way[N][N];void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=n;i++)    {        for(int j=1;j&lt;=m;j++)cin&gt;&gt;w[i][j];    }    for(int i=n;i;i--)    {        for(int j=1;j&lt;=m;j++)        {            for(int k=0;k&lt;=j;k++)            {                if(f[i][j]&lt;f[i+1][j-k]+w[i][k]){                    f[i][j]=f[i+1][j-k]+w[i][k];                    way[i][j]=k;                }            }        }    }    cout&lt;&lt;f[1][m]&lt;&lt;endl;    for(int i=1,j=m;i&lt;=n;i++)    {        cout&lt;&lt;i&lt;&lt;" "&lt;&lt;way[i][j]&lt;&lt;endl;        j-=way[i][j];    }}

金明的预算方案题目链接：P1064 [NOIP 2006 提高组] 金明的预算方案 - 洛谷思路：本质也是分组背包，每个主件代表一个组，附件是组中的物品。这样一个主件最多两附件，所以最多四种选法（一主、一主一附(两种)、一主两附、），这里用到了二进制思想去优化，具体见代码注释。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;#define x first#define y secondconst int N=2e5+5;PII a[N];//主件vector&lt;PII&gt; b[N];//附件，用pair存体积和对应主件int f[N];void solve(){    int n,m;    cin&gt;&gt;m&gt;&gt;n;    for(int i=1;i&lt;=n;i++)    {        int v,p,q;        cin&gt;&gt;v&gt;&gt;p&gt;&gt;q;        p*=v;        if(!q)a[i]={v,p};//主件        else b[q].push_back({v,p});//附件    }     //f[i][u]：前i个组中，体积不超过u的最大价值。    for(int i=1;i&lt;=n;i++)    {        if(!a[i].x)continue;        for(int u=m;u&gt;=0;u--)        {            for(int j=0;j&lt;1&lt;&lt;b[i].size();j++)            /*	            这里枚举附件数量，当附件数量为0时就不进行循环了。当附件为1时一共有2种(主(00)、主附(01))、附件数为2时(00\01\10\11)二进制思路            */            {                int v=a[i].x,w=a[i].y;//主件的体积和价值                for(int k=0;k&lt;b[i].size();k++)//二进制枚举                {                    if(j&gt;&gt;k&amp;1)//判断第k位是否为1，k只能为0和1                    {                        v+=b[i][k].x;//如果选了这个则加上对应附件的体积价值                        w+=b[i][k].y;                    }                }                if(u&gt;=v)f[u]=max(f[u],f[u-v]+w);//如果当前剩余的容量大于当前组合的体积更新价值            }        }    }    cout&lt;&lt;f[m];}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}


