P3916 图的遍历题目链接： https://www.luogu.com.cn/problem/P3916题目大意： 给出 N 个点，M 条边的有向图，对于每个点 v ，求 A(v) 表示从点 v 出发，能到达的编号最大的点。思路：看到这种一个点能到好几个点，然后还要找一个编号最大的点，第一个想到的应该就是 dfs 了。这里我们可以反向思维一下，如果反向建立连边的话，从序号较大的节点 dfs 如果一个节点被访问过，那么访问的起始点就是最大值了。这里介绍两种存图方式：邻接表存储（链式前向星）：
int h[N];  // 头指针数组，h[i]表示节点i的第一个邻接点在数组中的索引int e[M];  // 边数组，存储边的终点节点int ne[M]; // next数组，存储下一条邻接边的索引int idx;   // 当前可用的空位置索引void add(int a,int b)//a所对应的单链表中插入b a作为根{ 	e[idx]=b;	ne[idx]=h[a];	h[a]=idx++; }初始时会将h置为-1表示无邻接点idx初始值为0执行add函数时，add(1,2)e[0]=2,ne[0]=-1,h[1]=0;此时的链表结构 [1] -&gt; [2] -&gt; NULLfor(int i=h[x];i!=-1;i=ne[i])遍历方法
vector 存图
vector&lt;int&gt; p[N];p[b].push_back(a);这个存图看起来更简单for(int i=0;i&lt;p[x].size();i++)遍历也是
代码：
//邻接表存图#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=1e5+5;int h[N],e[N],ne[N],idx,ans[N];void add(int a,int b)//a所对应的单链表中插入b  a作为根 {    e[idx]=b;    ne[idx]=h[a];    h[a]=idx++;}//h[x]邻接表存储树，有n个节点，所以需要n个队列头节点//e[x]存储元素//ne[x]存储列表的next值void dfs(int x,int d){    if(ans[x]) return;    ans[x]=d;    for(int i=h[x];i!=-1;i=ne[i]){        int y=e[i];        dfs(y,d);//递归标记所有邻接点    }}void solve(){    memset(h,-1,sizeof h);    int n,m;    cin&gt;&gt;n&gt;&gt;m;    for(int i=0;i&lt;m;i++)    {        int a,b;        cin&gt;&gt;a&gt;&gt;b;        add(b,a);    }    for(int i=n;i&gt;0;i--)    {        if(!ans[i])dfs(i,i);    }    for(int i=1;i&lt;=n;i++)cout&lt;&lt;ans[i]&lt;&lt;" ";}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

