Cow Picnic S题目链接： https://www.luogu.com.cn/problem/P3916题目大意： 找到所有奶牛都可达的牧场数量。思路： 我们可以以每头牛所在的牧场为起点，去进行 dfs，对于一个牧场遍历到一次计数器加一，找到遍历次数等于 k 的牧场。这里为了防止环路需要用到 st 数组，用完记得恢复状态。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=1e5+5;vector&lt;int&gt; p[N];//用链式存储也是一样的/*void add(int a,int b){	e[idx]=b;	ne[idx]=h[a];	h[a]=idx++;}可以自己完善下*/int c[105];int cnt[1005];int ans;int st[1005];//为了防止环路，放个st//用st的时候不要忘记恢复状态void dfs(int x){    st[x]=1;    cnt[x]++;    for(int i=0;i&lt;p[x].size();i++)    {        if(!st[p[x][i]])dfs(p[x][i]);    }}void solve(){    int k,m,n;    cin&gt;&gt;k&gt;&gt;n&gt;&gt;m;    for(int i=1;i&lt;=k;i++)    {        cin&gt;&gt;c[i];    }    for(int i=1;i&lt;=m;i++)    {        int a,b;        cin&gt;&gt;a&gt;&gt;b;        p[a].push_back(b);    }    for(int i=1;i&lt;=k;i++){        memset(st,0,sizeof st);        dfs(c[i]);     }     for(int i=1;i&lt;=n;i++)    {        if(cnt[i]==k)ans++;    }    cout&lt;&lt;ans;}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

P4779 【模板】单源最短路径（标准版）题目链接： https://www.luogu.com.cn/problem/P4779思路： 单源最短路，无负权值，是一道 dijkstra 的题。 死去的数据结构知识在攻击我。🐒🐒 首先初始化所有节点的距离为无穷大，起点距离为 0，使用优先队列维护，优先处理距离最小的节点，遍历其所有邻接边，更新节点距离。一直重复直到队列为空。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);typedef pair&lt;int,int&gt; PII;priority_queue&lt;PII,vector&lt;PII&gt;,greater&lt;PII&gt;&gt; que;const int M=2e5+5;const int N=1e5+5;int dis[N];//用于存储每个点到起点的最短距离bool st[N];//用于在更新最短距离时 判断当前的点的最短距离是否确定 是否需要更新int e[M],ne[M],h[N],idx,w[M];void add(int a,int b,int c){    e[idx]=b;    ne[idx]=h[a];    w[idx]=c;    h[a]=idx++;}void dijkstra(int s){    memset(dis, 0x3f, sizeof dis);    que.push({0,s});//源点到自己距离是0；    dis[s]=0;    while(!que.empty())    {        auto x=que.top();        que.pop();        int dist=x.first,v=x.second;        if(!st[v])        {            for(int i=h[v];i!=-1;i=ne[i])            {                int j=e[i];                if(dis[j]&gt;dist+w[i])                {                    dis[j]=dist+w[i];                    que.push({dis[j],j});                }            }            st[v]=true;        }    }}void solve(){    int n,m,s;    cin&gt;&gt;n&gt;&gt;m&gt;&gt;s;    memset(h,-1,sizeof h);    for(int i=1;i&lt;=m;i++)    {        int u,v,w;        cin&gt;&gt;u&gt;&gt;v&gt;&gt;w;        add(u,v,w);    }    dijkstra(s);    for(int i=1;i&lt;=n;i++)cout&lt;&lt;dis[i]&lt;&lt;" ";}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

P1144 最短路计数题目链接： https://www.luogu.com.cn/problem/P1144思路： 无向图，边权都是 1，这里继续使用dijkstra。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);typedef pair&lt;int,int&gt; PII;const int M=4e6+5;//这里注意无向图，二倍，不然会被被卡一个const int N=1e6+5;const int MOD=100003;priority_queue&lt;PII,vector&lt;PII&gt;,greater&lt;PII&gt;&gt;que;int dis[N];//用于存储每个点到起点的最短距离int e[M],ne[M],h[N],idx,w[M];bool st[N];int ans[N];void add(int a,int b,int c){    e[idx]=b;    ne[idx]=h[a];    w[idx]=c;    h[a]=idx++;}void dijkstra(int s){    que.push({0,s});    dis[s]=0;    while(!que.empty())    {        auto x=que.top();        que.pop();        int dist=x.first,v=x.second;        if(!st[v])        {            for(int i=h[v];i!=-1;i=ne[i])            {                int j=e[i];                if(dis[j]&gt;dist+w[i])                {                    dis[j]=dist+w[i];                    ans[j]=ans[v];//路径数重置为前驱节点的路径数                    que.push({dis[j],j});                }else if(dis[j]==dist+w[i])                {                    ans[j]=(ans[v]+ans[j])%MOD;//// 累加路径数                }            }            st[v]=true;        }    }        }void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    memset(h,-1,sizeof h);    memset(dis,0x3f,sizeof dis);    for(int i=1;i&lt;=m;i++)    {        int x,y;        cin&gt;&gt;x&gt;&gt;y;        add(x,y,1);        add(y,x,1);    }    ans[1]=1;    dijkstra(1);    for(int i=1;i&lt;=n;i++)    {        if(dis[i]==0x3f3f3f3f)cout&lt;&lt;"0"&lt;&lt;endl;        else cout&lt;&lt;ans[i]&lt;&lt;endl;    }}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}
P1462 通往奥格瑞玛的道路题目链接： https://www.luogu.com.cn/problem/P1462题目大意： 要找出满足能走通到终点的最少的钱，血量还要够，思路： 看到最值了，考虑下二分，对于费用进行二分，对于血量用最短路。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);typedef pair&lt;int,int&gt; PII;const int M=2e5+5;const int N=1e4+5;int f[N];int dis[N];//用于存储每个点到起点的血量消耗bool st[N];//用于在更新最短距离时 判断当前的点的最短距离是否确定 是否需要更新int e[M],ne[M],h[N],idx,w[M];int n,m,b;void add(int a,int b,int c){    e[idx]=b;    ne[idx]=h[a];    w[idx]=c;    h[a]=idx++;}bool dijkstra(int maxcost){    if(f[1]&gt;maxcost||f[n]&gt;maxcost)return false;    memset(st,0,sizeof st);    memset(dis,0x3f,sizeof dis);    priority_queue&lt;PII,vector&lt;PII&gt;,greater&lt;PII&gt;&gt; que;    //从第一个城市0血出发，每经过一条边就增加对应的血量，如果血量超过b说明不行    que.push({0,1});//源点到自己距离是0；    dis[1]=0;    while(!que.empty())    {        auto x=que.top();        que.pop();        int dist=x.first,v=x.second;        if(!st[v])        {            for(int i=h[v];i!=-1;i=ne[i])            {                int j=e[i];                if(f[j]&gt;maxcost) continue;//钱超了                if(dist+w[i]&gt;b) continue;//血量超了                if(dis[j]&gt;dist+w[i]){                    dis[j]=dist+w[i];                    que.push({dis[j],j});                }            }            st[v]=true;        }    }    if(dis[n]&lt;=b)return true;    else return false;}void solve(){    cin&gt;&gt;n&gt;&gt;m&gt;&gt;b;    memset(h,-1,sizeof h);    int l=0x3f3f3f3f,r=-1;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;f[i];        l=min(l,f[i]);        r=max(r,f[i]);    }    for(int i=1;i&lt;=m;i++)    {        int u,v,c;        cin&gt;&gt;u&gt;&gt;v&gt;&gt;c;        add(u,v,c);        add(v,u,c);    }    int ans=-1;    while(l&lt;=r)    {        int mid=(l+r)&gt;&gt;1;        if(dijkstra(mid)){            ans=mid;            r=mid-1;        }else l=mid+1;    }    if(ans!=-1)cout&lt;&lt;ans;    else cout&lt;&lt;"AFK";}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

