H - 乐链接： https://atcoder.jp/contests/abc438/tasks/abc438_e分析：用 st[N][35] 来表示第 i 个水桶，传递了  次后这个桶在谁手里把每个桶的初始状态都设为 st[i][0] 表示传递 0 次，桶还在自己手里。这里用二进制来拼凑出总步数。比如 10 的二进制是 用 sum[N][35] 来表示第 i 个水桶，经过  次操作后，会积累多少水。初始时 sum[i][0]=i代码实现：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int N=2e5+5;int st[N][35];//用来表示第i个水桶，传递了2的j次后这个桶在谁手里//这里用二进制的思想，把一个数拆分。int sum[N][35];void solve(){    int n,q;    cin&gt;&gt;n&gt;&gt;q;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;st[i][0];        sum[i][0]=i;    }    for(int i=1;i&lt;31;i++)//对于int类型的二进制数最多只有31位    {        //递归计算        for(int j=1;j&lt;=n;j++)//桶编号        {            st[j][i]=st[st[j][i-1]][i-1];            sum[j][i]=sum[j][i-1]+sum[st[j][i-1]][i-1];        }    }    while(q--)    {        int t,b;        cin&gt;&gt;t&gt;&gt;b;        int ans=0;        for(int i=0;i&lt;31;i++)        {            if(t&gt;&gt;i&amp;1){                ans+=sum[b][i];                b=st[b][i];            }        }        cout&lt;&lt;ans&lt;&lt;endl;    }}signed main(){	IOS	int t=1;	while(t--)	{		solve();	}}

