#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;const int N=2e5+5;int c[N];const int M=4e5+5;int e[N],ne[M],h[M],idx,w[M];int dist[N];bool st[N];void add(int a,int b,int c){    e[idx]=b;    w[idx]=c;    ne[idx]=h[a];    h[a]=idx++;}void bfs(int u,int v){    memset(dist,0x3f,sizeof dist);    memset(st,0,sizeof st);    dist[u]=0;    queue&lt;int&gt;q;    q.push(u);    while(q.size()){        auto t=q.front();        q.pop();        for(int i=h[t];i!=-1;i=ne[i]){            int j=e[i];            if(dist[j]&gt;dist[t]+w[i]){                dist[j]=dist[t]+w[i];                q.push(j);            }        }    }    cout&lt;&lt;dist[v]&lt;&lt;endl;}void solve(){    int n,m;    cin&gt;&gt;n&gt;&gt;m;    memset(h,-1,sizeof h);    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;c[i];    }    for(int i=1;i&lt;n;i++){        int u,v;        cin&gt;&gt;u&gt;&gt;v;        u=c[u],v=c[v];        add(u,v,1);        add(v,u,1);    }    while(m--){        int s,t;        cin&gt;&gt;s&gt;&gt;t;        bfs(c[s],c[t]);    }}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}
