AcWing 91. 最短Hamilton路径这个题如果暴力去做是会 TLE 的，这里就用到上面说的优化就是状压 DP。我们可以用二进制数来表示哪些点走过，0 表示没走，1 表示走了。当二进制数全为 1 时就代表走完了。2n的二进制表示为 1111…11
这里我们分析一下 DP，我们这里需要输出的也是最优解，所以 fi, j表示经过 i 集合的所有点到 j 点的最短 Hamilton 路径，属性就是最小值。那么就不难得到状态转移方程：f[i]][j]=min (f[i][j], f[i^(1&lt;&lt;j)][k]+weight[k][j])。

这里的 weight 数组是权值，表示从 k 点到 j 的距离。
i^(1&lt;&lt;j) 的意思是，i 异或 1 右移 j 位，具体来说就是 i 这个方案集合 xor 10……0, (其中 1 的位置在第 j 位)。其实就是将 i 的第 j 位改为 0，这样就符合了走到点 k的路径就不能经过点 j这个条件。
如果 i 的第 j 位上是 1 那么将其改为 0；
否则将 i 的第 j 位改为 1；可能表述的比较混乱，具体逻辑在代码中体现



#include &lt;bits/stdc++.h&gt;using namespace std;const int N=20,M=1&lt;&lt;N;//一共最多有20个1种状态//解释一下1&lt;&lt;N：因为i是二进制数，表示从0到当前点的状态，所以每个点都有两个状态0和1，所以是2的N次方int n,i,j,k,f[M][N],w[N][N];//f[i][j]:所有从0走到j,走过的所有点的情况是i的所有路径//f记录距离的总和例如f[2][4]表示第两种情况，从0号点到4号点的距离总和。//w用来存储点与点之间的距离权重int main(){    cin&gt;&gt;n;    for(i=0;i&lt;n;i++)        for(j=0;j&lt;n;j++)            cin&gt;&gt;w[i][j];    memset(f,0x3f,sizeof f);//f的属性是最小值，这里先设为最大值    f[1][0]=0;////第一个点是不需要任何费用的    for(i=1;i&lt;1&lt;&lt;n;i++)//i是遍历所有状态，从000000000到1111111111    {        for(j=0;j&lt;n;j++)//j遍历每个点。        {            if(i&gt;&gt;j&amp;1)//如果i集合中第j位是1，也就是到达过这个点            //k表示走到j这个点之前，以k为终点的最短距离            for(k=0;k&lt;n;k++)            {                if((i^(1&lt;&lt;j))&gt;&gt;k&amp;1)//i除去j这个点后包含k这个点            //如果从当前状态经过点集i中，去掉点j后，i仍然包含点k，那么才能从点k转移到点j。            //当然这个if也可以不加，因为如果i去掉第j个点后，i不包含点k了，            //那么f[i^1&lt;&lt;j][k]必然为正无穷，也就必然不会更新f[i][j]，所以去掉也可以AC。                {                    f[i][j]=min(f[i][j],f[i^(1&lt;&lt;j)][k]+w[k][j]);                }            }        }            }    cout&lt;&lt;f[(1&lt;&lt;n)-1][n-1];    //(1&lt;&lt;n)-1表示：有n个1，也就是所有的点都走完了    //n-1表示：终点    return 0;}
AcWing 998. 起床困难综合症这个题一共有 3 种操作，要得到经过 n 次操作后的最大值，这几个运算只有关该位上的数，不影响其他位上的数。所以我们可以从高到低来确定数的每一位。如果这一位上可以填 u 并且填 u 之后答案的该位是 1，那么在该位填 u 否则填!u;
问题来了，如何确定该位可以填几？

如果该位填 1 后，所得的数大于 m，那么该位填 0
否则如果该位填 1 后所得的数对 n 个数都运算之后结果小于等于该位填 0 之后得到的结果，那么为了让剩下的能填的数更大，该位填0；
否则该位填 1；确定好每一位之后就可以得到 ans 的值

#include &lt;bits/stdc++.h&gt;using namespace std;const int N=1e5+5;int n,m;int ans;int t[N];short op[N];// op 存 n 个数对应的操作，1表示按位或，2表示按位异或，3表示与string s;bool calc(bool x,int j)// calc 用于计算 x 经过所有数的第 j 位操作后所得到的结果{    for(int i=0;i&lt;n;i++)    {        if(op[i]==1) x|=t[i]&gt;&gt;j&amp;1;        else if(op[i]==2) x^=t[i]&gt;&gt;j&amp;1;        else x&amp;=t[i] &gt;&gt; j &amp; 1;    }    return x;}int main(){    cin&gt;&gt;n&gt;&gt;m;    for(int i=0;i&lt;n;i++)    {        cin&gt;&gt;s&gt;&gt;t[i];        if(s=="OR")op[i]=1;        else if(s=="XOR")op[i]=2;        else op[i]=3;    }    //本题中m最大是10^9，log2(10^9)=3log2(10^3)&lt;3*10=30，所以每次i从29往后枚举就可以了    for(int i=29;i&gt;=0;i--)    {         if(1&lt;&lt;i&lt;=m)//如果填1后小于等于m，要看填完后对答案的影响来填         {            bool x=calc(0,i),y=calc(1,i);            if(x&gt;=y) ans|=x&lt;&lt;i;//如果该位填1并不比该位填0更优，那么为了让剩下能填的数更大，在该位填0            else ans|=y&lt;&lt;i,m-=1&lt;&lt;i;            //否则在该位填1，填完后让m减去该位填1的结果，这样在后面填数的时候只用考虑是否大于m就可以了         }else ans|=calc(0,i)&lt;&lt;i;// 否则该位只能填 0    }    cout&lt;&lt;ans;    return 0;}
