Leetcode 3370. 仅含置位位的最小整数这个题是要求大于等于 n 的第一个二进制位全为 1 的数，所以我们求出 n 的二进制位数 m，返回长为 m 的全为 1 的二进制数即可
class Solution {public:    int smallestNumber(int n) {        int ans=0;        while(n){            ans=ans&lt;&lt;1|1;            //这个操作是将ans不断左移，然后通过按位或的操作将1加到最低位上            n&gt;&gt;=1;            //这里把n右移减小位数        }        return ans;    }};
这里呢灵茶的代码是这样的
class Solution {public:    int smallestNumber(int n) {        return (1 &lt;&lt; bit_width((uint32_t) n)) - 1;        //这里用bit_width计算无符号32位整数的二进制表示的位宽，然后左移bit_width((uint32_t) n)位，使其最高位为1，减一操作得到一个全为1的二进制数    }};
Leetcode 3226. 使两个整数相等的位更改次数这里我们运用集合与集合的思想，n ,k为两个不同的集合，如果可以使 n 修改为 k，我们是从 n 中去掉元素使其等于 k，那么 k 应该为 n 的子集。否则返回-1，满足这一条件后，我们可以通过对称差 (按位异或) 操作来得到需要去除的元素。这里因为 k 是子集所以得到的元素都是 n 独有的。通过 __builtin_popcount(n^k) 操作可以得到二进制中 1 的位数。验证是否为子集还可以通过求 n 和 k 的并集(按位或运算)验证是否为 n
class Solution {public:    int minChanges(int n, int k) {        return (n&amp;k)!=k ? -1:__builtin_popcount(n^k);        //return  (n|k)!= n ? -1:__builtin_popcount(n^k);    }};
Leetcode 1356. 根据数字二进制下 1 的数目排序class Solution {public:    vector&lt;int&gt; sortByBits(vector&lt;int&gt;&amp; arr) {        sort(arr.begin(),arr.end(),[&amp;](int x, int y){            int x1=__builtin_popcount(x);            int y1=__builtin_popcount(y);            if(x1&lt;y1) return true;            if(x1&gt;y1) return false;            return x&lt;y;        });        return arr;    }};
Leetcode  461. 汉明距离这个题其实就是问两个集合中不同的元素有多少，那我们就可以继续沿用对称差方法，求出集合再用 __builtin_popcount() 来求出集合中的元素数目
class Solution {public:    int hammingDistance(int x, int y) {        return __builtin_popcount(x^y);    }};
虽然直接用公式做题比较爽但是也学习一下用代码写这个操作
class Solution {public:    int hammingDistance(int x, int y) {        int s=x^y,cnt=0;        while(s){            cnt+=s&amp;1;            s&gt;&gt;=1;        }        return cnt;    }};
Leetcode 2220. 转换数字的最少位翻转次数这个题目和之前的类似，只是多了一个可以增加元素的操作，所以仍然是按位异或得到集合 s，这个集合包含 state 中独有的 (需要删除的元素) 和 goal 中独有的 (需要添加的元素)
class Solution {public:    int minBitFlips(int start, int goal) {        int s=start^goal;        return __builtin_popcount(s);    }};
Leetcode 1342. 将数字变成 0 的操作次数这个题一般模拟就可以过, 就不写位运算了
class Solution {public:    int numberOfSteps(int num) {        int ans=0;        while(num)        {            if(num%2){                num--;            }else num/=2;            ans++;        }        return ans;    }};
Leetcode 476. 数字的补数我们从左边到右边找到该二进制的第一个 1，t - 1，则该位后面的数都是 1111 这样形式，数字取反后和 t 与操作表明取取反结果后面的二进制
class Solution {public:    int findComplement(int num) {        if(!num) return 1;        int t=0;        for(int i=30;i&gt;=0;i--)        {            if(num&gt;&gt;i&amp;1){                t=1&lt;&lt;i;                break;            }        }        t--;        return ~num&amp;t;    }};
Leetcode 1009. 十进制整数的反码这个题用上面的代码就可以过了
class Solution {public:    int findComplement(int num) {        if(!num) return 1;        int t=0;        for(int i=30;i&gt;=0;i--)        {            if(num&gt;&gt;i&amp;1){                t=1&lt;&lt;i;                break;            }        }        t--;        return ~num&amp;t;    }};
也看到了用掩码做题的；那就来学习一下吧
class Solution {public:    int bitwiseComplement(int n) {        if (n==0) return 1; // 特殊情况处理        int ans=1;          // 初始化掩码为 1        while(ans&lt;=n){    // 循环直到掩码大于 n            ans&lt;&lt;=1;        // 将掩码左移一位        }        return ans-1-n;   // 计算补数    }};
Leetcode 868. 二进制间距这个题要求相邻 1 的最远距离，我们可以每次取 n 最后一位判断是否为 1，如果上一位为 1 则更新距离
class Solution {public:    int binaryGap(int n) {        int l=-1,ans=0;        for(int i=0;n;i++)        {            if(n&amp;1)            {                if(l!=-1)                {                    ans=max(ans,i-l);                }                l=i;            }            n&gt;&gt;=1;        }        return ans;    }};
Leetcode 2917. 找出数组中的 K-or 值这里我们枚举每个元素的 0~30 比特位，统计该位为 1 的个数再对 ans 进行操作
class Solution {public:    int findKOr(vector&lt;int&gt;&amp; nums, int k) {        int ans=0;        for(int i=0;i&lt;31;i++)        {            int cnt1=0;            for(int x:nums){                cnt1+=x&gt;&gt;i&amp;1;            }            if(cnt1&gt;=k){                ans|=1&lt;&lt;i;            }        }    }    return ans;};
Leetcode 693. 交替位二进制数我的想法就是逐步遍历每一个二进制位
class Solution {public:    bool hasAlternatingBits(int n) {        int l=0;        while(n){            if(n&amp;1)            {                if(l==1){                    return false;                }                l=1;                n&gt;&gt;=1;            }else {                if(l==-1){                    return false;                }                l=-1;                n&gt;&gt;=1;            }        }        return true;    }};
这样看起来就很复杂所以可以优化一下
class Solution {public:    bool hasAlternatingBits(int n) {        int l=-1;        for(;n;n&gt;&gt;=1)        {            if(l==(n&amp;1)) return false;            l=n&amp;1;        }        return true;    }};
Leetcode 2657. 找到两个数组的前缀公共数组这里是要取两个集合的交集，我们可以用 set 来去重，把两个数组中的元素均存入 set 中，然后减去 set 的大小即为重复元素的数量。
class Solution {public:    vector&lt;int&gt; findThePrefixCommonArray(vector&lt;int&gt;&amp; A, vector&lt;int&gt;&amp; B) {        int n=A.size();        vector&lt;int&gt; c;        unordered_set&lt;int&gt; cnt;        for(int i=0;i&lt;n;i++)        {            cnt.insert(A[i]);            cnt.insert(B[i]);            c.push_back(2*(i+1)-cnt.size());        }        return c;    }};
看看灵神的优雅代码把
class Solution {public:    vector&lt;int&gt; findThePrefixCommonArray(vector&lt;int&gt;&amp; A, vector&lt;int&gt;&amp; B) {        uint64_t p=0,q=0;//初始化两个 64 位无符号整数 p 和 q，用于存储两个数组中元素的位掩码。        for(int i=0;i&lt;A.size();i++)        {            p|=1ULL&lt;&lt;A[i];    //将a[i]的位置在p中标记为1。1ULL&lt;&lt;a[i]生成一个只有第a[i]位为1的二进制数，然后与p进行按位或操作，将该位置标记为1。            q|=1ULL&lt;&lt;B[i];            A[i]=popcount(p&amp;q);            //计算 p 和 q 的按位与结果中 1 的个数，即两个数组中相同元素的个数。        }        return A;    }};
Leetcode 231. 2 的幂这个问的是 2 的幂次，而不是偶数，如果 n 小于等于 0 那结果一定为 false。否则如果 n 是 2 的幂其二进制表示应该从第一位开始数第一个 1 即为最高位，也就是只有一个 1 。这个呢就是进行一次 lowbit 运算。
class Solution {public:    bool isPowerOfTwo(int n) {        return n&gt;0&amp;&amp;((n&amp;-n)==n);    }};
这里的判断方法还可以是我们对 n 减 1 再和 n 进行与运算
class Solution {public:    bool isPowerOfTwo(int n) {        return n&gt;0&amp;&amp;(n&amp;(n-1))==0;    }};
Leetcode 342. 4 的幂可以确定一个数如果是 4 的幂一定是 2 的幂，那么就可以开平方后再验证是否为 2 的幂
class Solution {public:    bool isPowerOfFour(int n) {        if(n&lt;=0)return false;        int t=sqrt(n);        return t*t==n&amp;&amp;(t&amp;(t-1))==0;    }};
Leetcode 191. 位 1 的个数这个题一般思想就是直接遍历
class Solution {public:    int hammingWeight(int n) {        int ans=0;        for(int i=0;i&lt;32;i++)        {            if(n&amp;(1&lt;&lt;i)) ans++;        }        return ans;    }};
当然也可以找找捷径直接用函数
class Solution {public:    int hammingWeight(int n) {        return __builtin_popcount(n);    }};
Leetcode 338. 比特位计数class Solution {public:    vector&lt;int&gt; countBits(int n) {        vector&lt;int&gt; a(n+1);        for(int i=0;i&lt;=n;i++)        {            a[i]=__builtin_popcount(i);        }        return a;    }};
Leetcode 2595. 奇偶位数class Solution {public:    vector&lt;int&gt; evenOddBit(int n) {        vector&lt;int&gt; ans(2);        for(int i=0;i&lt;32;i++)        {            if(n&amp;(1&lt;&lt;i)){                if(i%2) ans[1]++;                else ans[0]++;            }        }        return ans;    }};
Leetcode 2154. 将找到的值乘以 2这个题我们可以用哈希表记录数组元素，再用函数判断元素是否在数组中。
class Solution {public:    int findFinalValue(vector&lt;int&gt;&amp; nums, int original) {        unordered_set&lt;int&gt; s(nums.begin(),nums.end());        while(s.count(original))original*=2;        return original;    }};
也可以排序一下直接找
class Solution {public:    int findFinalValue(vector&lt;int&gt;&amp; nums, int original) {        sort(nums.begin(),nums.end());        for(auto x:nums)        {            if(x==original) original*=2;        }        return original;    }};
