const int N=2e5+5;int a[N];int dp[N][2];void solve(){    int n;    cin&gt;&gt;n;    memset(dp,0x3f,sizeof dp);    bool falg=true;    for(int i=1;i&lt;=n;i++)    {        cin&gt;&gt;a[i];        if(a[i]!=1)falg=false;    }    if(falg){        cout&lt;&lt;n&lt;&lt;endl;        return;    }    int cnt=0;    dp[1][0]=0;dp[1][1]=1;    for(int i=2;i&lt;=n;i++)    {        if(__gcd(a[i],a[i-1])!=1)dp[i][0]=min(dp[i-1][1],dp[i-1][0]);        else dp[i][0]=dp[i-1][1];        dp[i][1]=min(dp[i-1][0],dp[i-1][1])+1;            }    cout&lt;&lt;min(dp[n][1],dp[n][0])&lt;&lt;endl;}
