#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'const int N=2e5+5;int a[N];void solve(){    int n;    cin&gt;&gt;n;    int sum=0;    int cnt=0;    for(int i=1;i&lt;=n;i++){        cin&gt;&gt;a[i];        sum+=a[i]*(n-1);        if(a[i]%2)cnt++;    }    int ans=sum-cnt*(n-cnt);    cout&lt;&lt;ans/2&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	while(t--)	{		solve();	}}

镜像思路：本质是最短路。先来明确一下，只有个位不为 0 时才能反转，反转不会改变位数。首先先来检测一下 a 是否比 b 大一位。如果大的话输出 -1。之后使用队列维护每一个遇到的值，使用 pair 来存储 {当前值,到达当前值的操作次数}。这样的话可能就会遍历很多，所以能剪枝的尽量剪。代码：
#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);#define endl '\n'#define PII pair&lt;int,int&gt;int a,b,k;int rev(int x){    int res=0;    while(x&gt;0){        res=x%10+res*10;        x/=10;    }    return res;}void solve(){    cin&gt;&gt;a&gt;&gt;b&gt;&gt;k;    if(a==b){        cout&lt;&lt;"0"&lt;&lt;endl;        return;    }    queue&lt;PII&gt; q;    q.push({a,0});    int ans=-1;    int mx=1;    while(mx&lt;b)mx*=10;    if(a&gt;=mx){        cout&lt;&lt;"-1"&lt;&lt;endl;        return;    }    vector&lt;int&gt; st(mx,0);    st[a]=1;    while(!q.empty()){        auto [x,cnt]=q.front();        q.pop();        if(x%10){            int r=rev(x);            if(r==b){                ans=cnt+1;                break;            }            if(r&lt;mx&amp;&amp;!st[r]){                st[r]=1;                q.push({r,cnt+1});            }        }        int m=x+k;        if(m==b){            ans=cnt+1;            break;        }        if(m&lt;mx&amp;&amp;!st[m]){            st[m]=1;            q.push({m,cnt+1});        }    }    cout&lt;&lt;ans&lt;&lt;endl;}signed main(){	IOS	int t;	cin&gt;&gt;t;	while(t--)	{		solve();	}}

