D Longest Subsequence思路：要求最长子序列，我们可以用 dp[x] 来记录以 x 结尾的最长子序列的长度，它只能从 dp[x-1] 或 dp[x+1] 上演变过来。所以 dp[x]=max(dp[x],max(dp[x-1],dp[x+1])+1)。代码：
void solve(){    int n;    cin&gt;&gt;n;    vector&lt;int&gt; a(n);    for(int i=0;i&lt;n;i++)    {        cin&gt;&gt;a[i];    }    vector&lt;int&gt; dp(n+5,0);    int ans=0;    for(int i=0;i&lt;n;i++)    {        int m=max(dp[a[i]+1],dp[a[i]-1])+1;        dp[a[i]]=max(m,dp[a[i]]);        ans=max(ans,dp[a[i]]);    }    cout&lt;&lt;ans&lt;&lt;endl;}
E Eat The Candy思路：对每一个盒子都计算它所能达到的最大值，最后取所有盒子的最大值。对于每个位置计算：从左边能搬多少糖到 i、从右边能搬多少糖到 i。代码：
void solve(){    int n;    cin&gt;&gt;n;    vector&lt;int&gt; a(n);    for(int i=0;i&lt;n;i++)    {        cin&gt;&gt;a[i];    }    vector&lt;int&gt; b(n),c(n);    int now=a[0];    for(int i=0;i&lt;n-1;i++)    {        b[i+1]=b[i]+min(a[i+1],now);        now=a[i+1]-min(a[i+1],now);    }    now=a[n-1];    for(int i=n-1;i&gt;=1;i--)    {        c[i-1]=c[i]+min(now,a[i-1]);        now=a[i-1]-min(a[i-1],now);    }    int ans=0;    for(int i=0;i&lt;n;i++)    {        int m=a[i];        if(i)m+=b[i-1];        if(i!=n-1)m+=c[i+1];        ans=max(ans,m);    }    cout&lt;&lt;ans&lt;&lt;endl;}
F Bracket Coloring思路：括号匹配想到用栈。每一对括号考虑其前后是否相同。代码：
const int MOD=998244353;void solve(){    int n;    cin&gt;&gt;n;    string s;    cin&gt;&gt;s;    int ans=1;    vector&lt;int&gt; st;    for(int i=0;i&lt;s.size();i++)    {        if(s[i]=='('){            if(i==0||s[i-1]==')')//如果是新的括号组的开始                st.push_back(1);            else st.push_back(0);//连续左括号中的一个        }else{            if(st.size()==1){//栈大小为1当前匹配的是最外层括号                ans=ans*2%MOD;            }else if(st.back()==1){//栈顶为1，这对括号独立                //序列中两个相邻位置的括号字符相同（同为 ‘(’或同为‘)’），则它们的颜色不能相同。                if(i==s.size()-1||s[i+1]=='(')                    ans=ans*2%MOD;            }            st.pop_back();        }    }    cout&lt;&lt;ans&lt;&lt;endl;}

