Balanced Array思路：滑动窗口。两个滑动窗口存储当前窗口的最大值和最小值，然后进行判断，进行左端点的更新。代码：
const int N=2e5+5;int a[N];int qma[N],qmi[N];void solve(){    int n;    cin&gt;&gt;n;    int ans=0;    for(int i=0;i&lt;n;i++)    {        cin&gt;&gt;a[i];    }    int h1=0,t1=-1;    int h2=0,t2=-1;    int l=0;    for(int r=0;r&lt;n;r++)    {        while(h1&lt;=t1&amp;&amp;a[qma[t1]]&lt;a[r])t1--;        qma[++t1]=r;        while(h2&lt;=t2&amp;&amp;a[qmi[t2]]&gt;a[r])t2--;        qmi[++t2]=r;        while(h1&lt;=t1&amp;&amp;h2&lt;=t2&amp;&amp;(a[qma[h1]]-a[qmi[h2]]&gt;1))//两个队列不为空，如果不满足条件，对应队头出队。        {            if(qma[h1]==l)h1++;            if(qmi[h2]==l)h2++;            l++;//左端点右移        }        ans+=r-l+1;        /*        计算以r为右端点方案的个数        [l,r],[l+1,r],...,[r-1,r],[r,r]        */    }    cout&lt;&lt;ans&lt;&lt;endl;}

Maximize The Sum思路：如果数组中全为 0，数组不会发生变化。一次修改后的三个数字的异或和变为 ，从这里可以看出修改后三个值是不可能得到全 1 的，除非数组本来都是 1。这样最多就只有 n-1。一个 1 可以变成两个 1，不断重复下去必然能得到 n-1 个 1。代码：
void solve(){    int n;    cin&gt;&gt;n;    string s;    cin&gt;&gt;s;    bool f0=1,f1=1;    for(int i=0;i&lt;n;i++)    {        if(s[i]=='1'){            f0=0;        }else{            f1=0;        }    }    if(f0)cout&lt;&lt;"0"&lt;&lt;endl;    else if(f1)cout&lt;&lt;n&lt;&lt;endl;    else cout&lt;&lt;n-1&lt;&lt;endl;}



