#include &lt;bits/stdc++.h&gt;using namespace std;#define int long long#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);const int MOD=1e9+7;int qmi(int a,int b){    int res=1;    while(b){        if(b&amp;1)res=res*a%MOD;        a=a*a%MOD;        b&gt;&gt;=1;    }    return res%MOD;}void solve(){    int n;    cin&gt;&gt;n;    int m=qmi(2,n-1);    int t=n;    for(int i=1;i&lt;=n;i++)    {        if(i==1)t=n;        else{            t=t*(n-i+1)%MOD;            t=t*qmi(i,MOD-2)%MOD;        }        cout&lt;&lt;t*m%MOD&lt;&lt;" ";    }}signed main(){	IOS	//int t;	//cin&gt;&gt;t;	int t=1;	while(t--)	{		solve();	}}

